loadstring([[local Rayfield=loadstring(game:HttpGet('https://sirius.menu/rayfield'))()local Window=Rayfield:CreateWindow({Name="Zayden's Monkey Mod Menu",LoadingTitle="Zayden's Monkey Mod Menu",LoadingSubtitle="Triston's a femboy 💅 | bomb tag survival go crazy",ConfigurationSaving={Enabled=true,FolderName="ZaydenMonkey",FileName="Config"}})local Players=game:GetService("Players")local UserInputService=game:GetService("UserInputService")local RunService=game:GetService("RunService")local LocalPlayer=Players.LocalPlayer local speedValue=16 local jumpValue=50 local infJumpEnabled=false local flying=false local noclipping=false local flySpeed=50 local flyBodyVelocity=nil local flyConnection=nil local noclipConnection=nil local hitboxEnabled=false local hitboxSize=10 local originalHRPSizes={}local boxAdornments={}local hitboxUpdateConnection=nil local autoTagEnabled=false local autoTagConnection=nil local lastTagTime={}UserInputService.JumpRequest:Connect(function()if infJumpEnabled and LocalPlayer.Character and LocalPlayer.Character:FindFirstChildOfClass("Humanoid")then LocalPlayer.Character:FindFirstChildOfClass("Humanoid"):ChangeState(Enum.HumanoidStateType.Jumping)end end)local function applyMovement()local character=LocalPlayer.Character if not character then return end local humanoid=character:FindFirstChildOfClass("Humanoid")if humanoid then humanoid.WalkSpeed=speedValue humanoid.JumpPower=jumpValue end end LocalPlayer.CharacterAdded:Connect(function()task.wait(0.5)applyMovement()end)local function updateOtherHitboxes()for _,player in ipairs(Players:GetPlayers())do if player~=LocalPlayer and player.Character then local char=player.Character local root=char:FindFirstChild("HumanoidRootPart")if root then if not originalHRPSizes[player.Name]then originalHRPSizes[player.Name]=root.Size end root.Size=Vector3.new(hitboxSize,hitboxSize,hitboxSize)if not boxAdornments[player.Name]then local adorn=Instance.new("BoxHandleAdornment")adorn.Name="MonkeyHitboxVisual"adorn.Adornee=root adorn.Size=Vector3.new(hitboxSize,hitboxSize,hitboxSize)adorn.Color3=Color3.fromRGB(100,100,100)adorn.Transparency=0.5 adorn.AlwaysOnTop=true adorn.ZIndex=1 adorn.Parent=root boxAdornments[player.Name]=adorn else boxAdornments[player.Name].Size=Vector3.new(hitboxSize,hitboxSize,hitboxSize)end end end end end local function enableHitboxExpander()if hitboxUpdateConnection then return end hitboxUpdateConnection=RunService.Heartbeat:Connect(updateOtherHitboxes)updateOtherHitboxes()end local function disableHitboxExpander()if hitboxUpdateConnection then hitboxUpdateConnection:Disconnect()hitboxUpdateConnection=nil end for playerName,originalSize in pairs(originalHRPSizes)do local player=Players:FindFirstChild(playerName)if player and player.Character then local root=player.Character:FindFirstChild("HumanoidRootPart")if root then root.Size=originalSize end end end for _,adorn in pairs(boxAdornments)do if adorn and adorn.Parent then adorn:Destroy()end end boxAdornments={}originalHRPSizes={}end local function startAutoTag()if autoTagConnection then return end autoTagConnection=RunService.Heartbeat:Connect(function()if not autoTagEnabled then return end local character=LocalPlayer.Character if not character or not character:FindFirstChild("HumanoidRootPart")then return end local root=character.HumanoidRootPart local hasBomb=false local bombPart=character:FindFirstChild("Bomb")or(character:FindFirstChild("Head")and character.Head:FindFirstChild("Bomb"))if bombPart then hasBomb=true end if not hasBomb then return end local now=tick()for _,player in ipairs(Players:GetPlayers())do if player~=LocalPlayer and player.Character then local targetChar=player.Character local targetRoot=targetChar:FindFirstChild("HumanoidRootPart")if targetRoot then local distance=(root.Position-targetRoot.Position).Magnitude if distance<(hitboxSize+8)then if not lastTagTime[player]or now-lastTagTime[player]>0.35 then local tagPart=bombPart or root firetouchinterest(tagPart,targetRoot,0)firetouchinterest(tagPart,targetRoot,1)lastTagTime[player]=now end end end end end end)end local function stopAutoTag()if autoTagConnection then autoTagConnection:Disconnect()autoTagConnection=nil end lastTagTime={}end local function startFly()if flying then return end flying=true local character=LocalPlayer.Character if not character or not character:FindFirstChild("HumanoidRootPart")then flying=false return end local root=character.HumanoidRootPart flyBodyVelocity=Instance.new("BodyVelocity")flyBodyVelocity.Name="MonkeyFly"flyBodyVelocity.MaxForce=Vector3.new(400000,400000,400000)flyBodyVelocity.Velocity=Vector3.new(0,0,0)flyBodyVelocity.Parent=root flyConnection=RunService.RenderStepped:Connect(function()if not flying or not root or not flyBodyVelocity then return end local cam=workspace.CurrentCamera local moveDir=Vector3.new(0,0,0)if UserInputService:IsKeyDown(Enum.KeyCode.W)then moveDir+=cam.CFrame.LookVector end if UserInputService:IsKeyDown(Enum.KeyCode.S)then moveDir-=cam.CFrame.LookVector end if UserInputService:IsKeyDown(Enum.KeyCode.A)then moveDir-=cam.CFrame.RightVector end if UserInputService:IsKeyDown(Enum.KeyCode.D)then moveDir+=cam.CFrame.RightVector end if UserInputService:IsKeyDown(Enum.KeyCode.Space)then moveDir+=Vector3.new(0,1,0)end if UserInputService:IsKeyDown(Enum.KeyCode.LeftControl)then moveDir-=Vector3.new(0,1,0)end local magnitude=moveDir.Magnitude if magnitude>0 then flyBodyVelocity.Velocity=(moveDir/magnitude)*flySpeed else flyBodyVelocity.Velocity=Vector3.new(0,0,0)end end)end local function stopFly()if not flying then return end flying=false if flyConnection then flyConnection:Disconnect()end if flyBodyVelocity then flyBodyVelocity:Destroy()end flyConnection=nil flyBodyVelocity=nil end local function startNoclip()if noclipping then return end noclipping=true noclipConnection=RunService.Stepped:Connect(function()if not noclipping then return end local character=LocalPlayer.Character if character then for _,part in pairs(character:GetDescendants())do if part:IsA("BasePart")and part.CanCollide then part.CanCollide=false end end end end)end local function stopNoclip()if not noclipping then return end noclipping=false if noclipConnection then noclipConnection:Disconnect()end noclipConnection=nil end local MovementTab=Window:CreateTab("🐒 Movement",6023426923)MovementTab:CreateSection("Speed Boost")MovementTab:CreateSlider({Name="WalkSpeed",Range={16,500},Increment=1,Suffix=" studs/s",CurrentValue=16,Flag="SpeedSlider",Callback=function(value)speedValue=value applyMovement()end})MovementTab:CreateSection("Jump Boost")MovementTab:CreateSlider({Name="Jump Power",Range={50,500},Increment=1,Suffix=" studs",CurrentValue=50,Flag="JumpSlider",Callback=function(value)jumpValue=value applyMovement()end})MovementTab:CreateToggle({Name="Infinite Jump",CurrentValue=false,Flag="InfJumpToggle",Callback=function(value)infJumpEnabled=value end})MovementTab:CreateSection("Flight")MovementTab:CreateToggle({Name="Enable Fly (WASD + Space/Ctrl)",CurrentValue=false,Flag="FlyToggle",Callback=function(value)if value then startFly()else stopFly()end end})MovementTab:CreateSlider({Name="Fly Speed",Range={10,200},Increment=1,Suffix=" studs/s",CurrentValue=50,Flag="FlySpeedSlider",Callback=function(value)flySpeed=value end})MovementTab:CreateToggle({Name="Noclip (walk through walls)",CurrentValue=false,Flag="NoclipToggle",Callback=function(value)if value then startNoclip()else stopNoclip()end end})local ExtrasTab=Window:CreateTab("💥 Extras",6026568198)ExtrasTab:CreateSection("Survival & Tagging Helpers")ExtrasTab:CreateButton({Name="Super Monkey Mode (insane everything)",Callback=function()speedValue=250 jumpValue=350 infJumpEnabled=true applyMovement()Rayfield:Notify({Title="🐵 SUPER MONKEY MODE",Content="untouchable fr 🐒",Duration=6})end})ExtrasTab:CreateSection("Hitbox Expander (Other Players - Grey Box)")ExtrasTab:CreateToggle({Name="Hitbox Expander (Others)",CurrentValue=false,Flag="HitboxToggle",Callback=function(value)hitboxEnabled=value if value then enableHitboxExpander()else disableHitboxExpander()end end})ExtrasTab:CreateSlider({Name="Hitbox Size",Range={1,50},Increment=1,Suffix=" studs",CurrentValue=10,Flag="HitboxSlider",Callback=function(value)hitboxSize=value if hitboxEnabled then updateOtherHitboxes()end end})ExtrasTab:CreateSection("Auto Bomb Tag (only when you got it)")ExtrasTab:CreateToggle({Name="Auto Tag Players (Bomb Only)",CurrentValue=false,Flag="AutoTagToggle",Callback=function(value)autoTagEnabled=value if value then startAutoTag()else stopAutoTag()end end})ExtrasTab:CreateButton({Name="Reset Character (if stuck)",Callback=function()if LocalPlayer.Character then LocalPlayer.Character:BreakJoints()end end})ExtrasTab:CreateButton({Name="Rejoin Server",Callback=function()game:GetService("TeleportService"):Teleport(game.PlaceId,LocalPlayer)end})ExtrasTab:CreateSection("Monkey Fun")ExtrasTab:CreateButton({Name="Monkey Scream (loud af)",Callback=function()local sound=Instance.new("Sound")sound.SoundId="rbxassetid://131057983"sound.Volume=1 sound.Parent=workspace sound:Play()task.delay(3,function()sound:Destroy()end)Rayfield:Notify({Title="🐵 OOO OOO AA AA!",Content="monkey energy deployed",Duration=3})end})if LocalPlayer.Character then task.wait(0.5)applyMovement()end Rayfield:Notify({Title="🐵 Zayden's Monkey Mod Menu Loaded!",Content="Triston's a femboy 💅\nAuto bomb tag fixed + grey hitbox",Duration=8})]])()
